/*
 * Graph Abstract Data Type Implementation
 * Using Adjacency Matrix Representation
 * Supports: Directed, Undirected, Weighted Graphs
 */

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <string.h>

#define MAX_VERTICES 100
#define INF -1 // Represents no edge

typedef struct {
 int numVertices;
 int adjMatrix[MAX_VERTICES][MAX_VERTICES];
 char vertexLabels[MAX_VERTICES][32]; // Store vertex labels
 bool vertexExists[MAX_VERTICES];
 bool isDirected;
 bool isWeighted;
} Graph;

// Create and initialize an empty graph
Graph* createGraph(int maxVertices, bool directed, bool weighted) {
 Graph* g = (Graph*)malloc(sizeof(Graph));
 if (g == NULL) {
 printf("Memory allocation failed!\n");
 return NULL;
 }

 g->numVertices = 0;
 g->isDirected = directed;
 g->isWeighted = weighted;

 // Initialize adjacency matrix
 for (int i = 0; i < MAX_VERTICES; i++) {
 g->vertexExists[i] = false;
 g->vertexLabels[i][0] = '\0';
 for (int j = 0; j < MAX_VERTICES; j++) {
 g->adjMatrix[i][j] = INF; // No edge
 }
 }

 return g;
}

// Add a vertex to the graph
int addVertex(Graph* g, const char* label) {
 if (g->numVertices >= MAX_VERTICES) {
 printf("Graph is full! Cannot add more vertices.\n");
 return -1;
 }

 // Check if vertex already exists
 for (int i = 0; i < MAX_VERTICES; i++) {
 if (g->vertexExists[i] && strcmp(g->vertexLabels[i], label) == 0) {
 printf("Vertex '%s' already exists.\n", label);
 return i;
 }
 }

 // Find empty slot
 int index = -1;
 for (int i = 0; i < MAX_VERTICES; i++) {
 if (!g->vertexExists[i]) {
 index = i;
 break;
 }
 }

 strcpy(g->vertexLabels[index], label);
 g->vertexExists[index] = true;
 g->numVertices++;

 return index;
}

// Find vertex index by label
int findVertex(Graph* g, const char* label) {
 for (int i = 0; i < MAX_VERTICES; i++) {
 if (g->vertexExists[i] && strcmp(g->vertexLabels[i], label) == 0) {
 return i;
 }
 }
 return -1;
}

// Add an edge between two vertices
void addEdge(Graph* g, const char* u, const char* v, int weight) {
 int uIndex = findVertex(g, u);
 int vIndex = findVertex(g, v);

 // Add vertices if they don't exist
 if (uIndex == -1) uIndex = addVertex(g, u);
 if (vIndex == -1) vIndex = addVertex(g, v);

 int w = g->isWeighted ? weight : 1;

 // Add edge in adjacency matrix
 g->adjMatrix[uIndex][vIndex] = w;

 // For undirected graphs, add edge in reverse direction too
 if (!g->isDirected) {
 g->adjMatrix[vIndex][uIndex] = w;
 }

 printf("Edge added: %s <-> %s (weight: %d)\n", u, v, w);
}

// Remove an edge between two vertices
void removeEdge(Graph* g, const char* u, const char* v) {
 int uIndex = findVertex(g, u);
 int vIndex = findVertex(g, v);

 if (uIndex == -1 || vIndex == -1) {
 printf("One or both vertices not found!\n");
 return;
 }

 g->adjMatrix[uIndex][vIndex] = INF;
 if (!g->isDirected) {
 g->adjMatrix[vIndex][uIndex] = INF;
 }

 printf("Edge removed: %s - %s\n", u, v);
}

// Remove a vertex and all incident edges
void removeVertex(Graph* g, const char* label) {
 int vIndex = findVertex(g, label);

 if (vIndex == -1) {
 printf("Vertex '%s' not found!\n", label);
 return;
 }

 // Remove all edges incident to this vertex
 for (int i = 0; i < MAX_VERTICES; i++) {
 if (g->vertexExists[i]) {
 g->adjMatrix[vIndex][i] = INF;
 g->adjMatrix[i][vIndex] = INF;
 }
 }

 // Remove the vertex
 g->vertexExists[vIndex] = false;
 g->vertexLabels[vIndex][0] = '\0';
 g->numVertices--;

 printf("Vertex '%s' removed.\n", label);
}

// Check if two vertices are adjacent
bool isAdjacent(Graph* g, const char* u, const char* v) {
 int uIndex = findVertex(g, u);
 int vIndex = findVertex(g, v);

 if (uIndex == -1 || vIndex == -1) {
 return false;
 }

 return g->adjMatrix[uIndex][vIndex] != INF;
}

// Get neighbors of a vertex
void getNeighbors(Graph* g, const char* label) {
 int vIndex = findVertex(g, label);

 if (vIndex == -1) {
 printf("Vertex '%s' not found!\n", label);
 return;
 }

 printf("Neighbors of %s: ", label);
 bool found = false;

 for (int i = 0; i < MAX_VERTICES; i++) {
 if (g->vertexExists[i] && g->adjMatrix[vIndex][i] != INF) {
 if (g->isWeighted) {
 printf("%s(%d) ", g->vertexLabels[i], g->adjMatrix[vIndex][i]);
 } else {
 printf("%s ", g->vertexLabels[i]);
 }
 found = true;
 }
 }

 if (!found) printf("(none)");
 printf("\n");
}

// Get degree(s) of a vertex
void getDegree(Graph* g, const char* label) {
 int vIndex = findVertex(g, label);

 if (vIndex == -1) {
 printf("Vertex '%s' not found!\n", label);
 return;
 }

 if (g->isDirected) {
 int inDegree = 0, outDegree = 0;

 // Count in-degree (edges coming into vertex)
 for (int i = 0; i < MAX_VERTICES; i++) {
 if (g->vertexExists[i] && g->adjMatrix[i][vIndex] != INF) {
 inDegree++;
 }
 }

 // Count out-degree (edges going out from vertex)
 for (int i = 0; i < MAX_VERTICES; i++) {
 if (g->vertexExists[i] && g->adjMatrix[vIndex][i] != INF) {
 outDegree++;
 }
 }

 printf("Degree of %s: In-degree = %d, Out-degree = %d\n", 
 label, inDegree, outDegree);
 } else {
 int degree = 0;
 for (int i = 0; i < MAX_VERTICES; i++) {
 if (g->vertexExists[i] && g->adjMatrix[vIndex][i] != INF) {
 degree++;
 }
 }
 printf("Degree of %s: %d\n", label, degree);
 }
}

// Check if graph is empty
bool isEmpty(Graph* g) {
 return g->numVertices == 0;
}

// BFS for connectivity check
bool bfsReachable(Graph* g, int start, bool* visited) {
 int queue[MAX_VERTICES];
 int front = 0, rear = 0;

 queue[rear++] = start;
 visited[start] = true;

 while (front < rear) {
 int current = queue[front++];

 for (int i = 0; i < MAX_VERTICES; i++) {
 if (g->vertexExists[i] && g->adjMatrix[current][i] != INF && !visited[i]) {
 visited[i] = true;
 queue[rear++] = i;
 }
 }
 }

 return true;
}

// Check if graph is connected
bool isConnected(Graph* g) {
 if (isEmpty(g)) return true;

 // Find first existing vertex
 int start = -1;
 for (int i = 0; i < MAX_VERTICES; i++) {
 if (g->vertexExists[i]) {
 start = i;
 break;
 }
 }

 bool visited[MAX_VERTICES] = {false};
 bfsReachable(g, start, visited);

 // Check if all vertices were visited
 for (int i = 0; i < MAX_VERTICES; i++) {
 if (g->vertexExists[i] && !visited[i]) {
 return false;
 }
 }

 return true;
}

// Display the graph
void displayGraph(Graph* g) {
 printf("\n=================================\n");
 printf("Graph (Directed: %s, Weighted: %s)\n", 
 g->isDirected ? "Yes" : "No", 
 g->isWeighted ? "Yes" : "No");
 printf("Number of vertices: %d\n", g->numVertices);

 printf("\nAdjacency Matrix:\n");
 printf(" ");

 // Print column headers
 for (int i = 0; i < MAX_VERTICES; i++) {
 if (g->vertexExists[i]) {
 printf("%6s", g->vertexLabels[i]);
 }
 }
 printf("\n");

 // Print matrix
 for (int i = 0; i < MAX_VERTICES; i++) {
 if (g->vertexExists[i]) {
 printf("%6s", g->vertexLabels[i]);
 for (int j = 0; j < MAX_VERTICES; j++) {
 if (g->vertexExists[j]) {
 if (g->adjMatrix[i][j] == INF) {
 printf(" -");
 } else {
 printf("%6d", g->adjMatrix[i][j]);
 }
 }
 }
 printf("\n");
 }
 }
}

// Verify Handshaking Theorem
void verifyHandshaking(Graph* g) {
 if (g->isDirected) {
 printf("\nHandshaking Theorem applies to undirected graphs only.\n");
 return;
 }

 int sumDegrees = 0;

 for (int i = 0; i < MAX_VERTICES; i++) {
 if (g->vertexExists[i]) {
 int degree = 0;
 for (int j = 0; j < MAX_VERTICES; j++) {
 if (g->vertexExists[j] && g->adjMatrix[i][j] != INF) {
 degree++;
 }
 }
 sumDegrees += degree;
 printf("Degree of %s: %d\n", g->vertexLabels[i], degree);
 }
 }

 // Count edges
 int edgeCount = 0;
 for (int i = 0; i < MAX_VERTICES; i++) {
 for (int j = i + 1; j < MAX_VERTICES; j++) {
 if (g->adjMatrix[i][j] != INF) {
 edgeCount++;
 }
 }
 }

 printf("\nSum of degrees: %d\n", sumDegrees);
 printf("2 * |E|: %d\n", 2 * edgeCount);
 printf("Verified: %s\n", sumDegrees == 2 * edgeCount ? "YES" : "NO");
}

// Main function demonstrating Graph ADT operations
int main() {
 printf("========================================\n");
 printf(" Graph ADT Implementation Demo\n");
 printf("========================================\n");

 // Example 1: Undirected Unweighted Graph
 printf("\n--- Example 1: Undirected Unweighted Graph ---\n");
 Graph* g1 = createGraph(MAX_VERTICES, false, false);

 addEdge(g1, "A", "B");
 addEdge(g1, "A", "C");
 addEdge(g1, "B", "C");
 addEdge(g1, "B", "D");
 addEdge(g1, "C", "D");

 displayGraph(g1);

 printf("\nAdjacency Tests:");
 printf("\nIs A adjacent to C? %s", isAdjacent(g1, "A", "C") ? "Yes" : "No");
 printf("\nIs A adjacent to D? %s", isAdjacent(g1, "A", "D") ? "Yes" : "No");

 getNeighbors(g1, "B");
 getDegree(g1, "B");
 printf("Is graph connected? %s\n", isConnected(g1) ? "Yes" : "No");

 printf("\n--- Handshaking Theorem Verification ---\n");
 verifyHandshaking(g1);

 // Example 2: Directed Weighted Graph
 printf("\n\n--- Example 2: Directed Weighted Graph ---\n");
 Graph* g2 = createGraph(MAX_VERTICES, true, true);

 addEdge(g2, "A", "B", 5);
 addEdge(g2, "A", "C", 3);
 addEdge(g2, "B", "C", 2);
 addEdge(g2, "B", "D", 4);
 addEdge(g2, "C", "D", 1);

 displayGraph(g2);

 getDegree(g2, "B");
 getNeighbors(g2, "A");

 // Clean up
 free(g1);
 free(g2);

 return 0;
}

import java.util.*;

/**
 * Graph Abstract Data Type Implementation in Java
 * Supports both Adjacency List and Adjacency Matrix representations
 * Can represent: Directed/Undirected, Weighted/Unweighted graphs
 */
public class Graph<T> {

 private Map<T, List<T>> adjList; // Adjacency list representation
 private Map<T, Map<T, Integer>> adjMatrix; // Adjacency matrix with weights
 private boolean isDirected;
 private boolean isWeighted;
 private Set<T> vertices;
 private List<Edge<T>> edges;

 /**
 * Inner class to represent an edge
 */
 private static class Edge<T> {
 T source;
 T destination;
 int weight;

 Edge(T source, T destination, int weight) {
 this.source = source;
 this.destination = destination;
 this.weight = weight;
 }

 @Override
 public String toString() {
 return "(" + source + " -> " + destination + ", w: " + weight + ")";
 }
 }

 /**
 * Constructor to create an empty graph
 */
 public Graph(boolean directed, boolean weighted) {
 this.isDirected = directed;
 this.isWeighted = weighted;
 this.vertices = new HashSet<>();
 this.adjList = new HashMap<>();
 this.adjMatrix = new HashMap<>();
 this.edges = new ArrayList<>();
 }

 /**
 * Insert a vertex into the graph
 */
 public Graph<T> addVertex(T v) {
 if (!vertices.contains(v)) {
 vertices.add(v);
 adjList.put(v, new ArrayList<>());
 adjMatrix.put(v, new HashMap<>());
 }
 return this;
 }

 /**
 * Insert an edge between two vertices
 */
 public Graph<T> addEdge(T u, T v, int weight) {
 // Add vertices if they don't exist
 addVertex(u);
 addVertex(v);

 int w = isWeighted ? weight : 1;

 // Add to adjacency list
 adjList.get(u).add(v);
 if (!isDirected) {
 adjList.get(v).add(u);
 }

 // Add to adjacency matrix
 adjMatrix.get(u).put(v, w);
 if (!isDirected) {
 adjMatrix.get(v).put(u, w);
 }

 // Add to edges list
 edges.add(new Edge<>(u, v, w));
 if (!isDirected) {
 edges.add(new Edge<>(v, u, w));
 }

 return this;
 }

 /**
 * Remove an edge between two vertices
 */
 public Graph<T> removeEdge(T u, T v) {
 if (!vertices.contains(u) || !vertices.contains(v)) {
 return this;
 }

 // Remove from adjacency list
 adjList.get(u).remove(v);
 if (!isDirected) {
 adjList.get(v).remove(u);
 }

 // Remove from adjacency matrix
 adjMatrix.get(u).remove(v);
 if (!isDirected) {
 adjMatrix.get(v).remove(u);
 }

 // Remove from edges list
 edges.removeIf(e -> (e.source.equals(u) && e.destination.equals(v)) ||
 (e.source.equals(v) && e.destination.equals(u)));

 return this;
 }

 /**
 * Remove a vertex and all incident edges
 */
 public Graph<T> removeVertex(T v) {
 if (!vertices.contains(v)) {
 return this;
 }

 // Remove vertex from all adjacency lists
 for (T vertex : vertices) {
 adjList.get(vertex).remove(v);
 adjMatrix.get(vertex).remove(v);
 }

 // Remove vertex
 vertices.remove(v);
 adjList.remove(v);
 adjMatrix.remove(v);

 // Remove edges involving v
 edges.removeIf(e -> e.source.equals(v) || e.destination.equals(v));

 return this;
 }

 /**
 * Check if two vertices are adjacent
 */
 public boolean isAdjacent(T u, T v) {
 if (!vertices.contains(u) || !vertices.contains(v)) {
 return false;
 }
 return adjMatrix.get(u).containsKey(v);
 }

 /**
 * Get all neighbors of a vertex
 */
 public List<T> getNeighbors(T v) {
 if (!vertices.contains(v)) {
 return new ArrayList<>();
 }
 return new ArrayList<>(adjList.get(v));
 }

 /**
 * Get weight of edge between u and v
 */
 public int getEdgeWeight(T u, T v) {
 if (!isAdjacent(u, v)) {
 throw new IllegalArgumentException("No edge exists between " + u + " and " + v);
 }
 return adjMatrix.get(u).get(v);
 }

 /**
 * Get degree of a vertex
 * For directed graphs: returns int[2] = {inDegree, outDegree}
 * For undirected graphs: returns int[1] = {degree}
 */
 public int[] getDegree(T v) {
 if (!vertices.contains(v)) {
 return new int[] {0, 0};
 }

 if (isDirected) {
 int inDegree = 0;
 int outDegree = adjList.get(v).size();

 // Count in-degree
 for (T vertex : vertices) {
 if (adjList.get(vertex).contains(v)) {
 inDegree++;
 }
 }

 return new int[] {inDegree, outDegree};
 } else {
 return new int[] {adjList.get(v).size()};
 }
 }

 /**
 * Check if graph is empty
 */
 public boolean isEmpty() {
 return vertices.isEmpty();
 }

 /**
 * Get number of vertices
 */
 public int getVertexCount() {
 return vertices.size();
 }

 /**
 * Get number of edges
 */
 public int getEdgeCount() {
 return isDirected ? edges.size() : edges.size() / 2;
 }

 /**
 * Check if graph is connected (for undirected graphs)
 */
 public boolean isConnected() {
 if (isEmpty()) {
 return true;
 }

 if (isDirected) {
 return isStronglyConnected();
 }

 // BFS from first vertex
 T start = vertices.iterator().next();
 Set<T> visited = new HashSet<>();
 Queue<T> queue = new LinkedList<>();

 queue.offer(start);
 visited.add(start);

 while (!queue.isEmpty()) {
 T current = queue.poll();
 for (T neighbor : adjList.get(current)) {
 if (!visited.contains(neighbor)) {
 visited.add(neighbor);
 queue.offer(neighbor);
 }
 }
 }

 return visited.size() == vertices.size();
 }

 /**
 * Check if directed graph is strongly connected
 */
 private boolean isStronglyConnected() {
 for (T start : vertices) {
 if (!canReachAll(start)) {
 return false;
 }
 }
 return true;
 }

 /**
 * Check if from start vertex, all other vertices are reachable
 */
 private boolean canReachAll(T start) {
 Set<T> visited = new HashSet<>();
 Queue<T> queue = new LinkedList<>();

 queue.offer(start);
 visited.add(start);

 while (!queue.isEmpty()) {
 T current = queue.poll();
 for (T neighbor : adjList.get(current)) {
 if (!visited.contains(neighbor)) {
 visited.add(neighbor);
 queue.offer(neighbor);
 }
 }
 }

 return visited.size() == vertices.size();
 }

 /**
 * Verify Handshaking Theorem
 * Sum of degrees = 2 * |E| for undirected graphs
 */
 public boolean verifyHandshaking() {
 if (isDirected) {
 System.out.println("Handshaking Theorem applies to undirected graphs only.");
 return false;
 }

 int sumDegrees = 0;
 for (T v : vertices) {
 sumDegrees += getDegree(v)[0];
 }

 int twoE = 2 * getEdgeCount();
 System.out.println("Sum of degrees: " + sumDegrees);
 System.out.println("2 * |E|: " + twoE);

 return sumDegrees == twoE;
 }

 /**
 * Display the graph
 */
 public void display() {
 System.out.println("\n========================================");
 System.out.println("Graph (Directed: " + isDirected + ", Weighted: " + isWeighted + ")");
 System.out.println("Vertices: " + vertices);
 System.out.println("Number of vertices: " + getVertexCount());
 System.out.println("Number of edges: " + getEdgeCount());

 System.out.println("\nAdjacency List:");
 for (T v : vertices) {
 if (isWeighted) {
 System.out.print(v + " -> ");
 List<T> neighbors = adjList.get(v);
 for (int i = 0; i < neighbors.size(); i++) {
 T neighbor = neighbors.get(i);
 int weight = adjMatrix.get(v).get(neighbor);
 System.out.print(neighbor + "(w:" + weight + ")");
 if (i < neighbors.size() - 1) System.out.print(", ");
 }
 System.out.println();
 } else {
 System.out.println(v + " -> " + adjList.get(v));
 }
 }
 }

 /**
 * Main method for demonstration
 */
 public static void main(String[] args) {
 System.out.println("========================================");
 System.out.println(" Graph ADT Implementation in Java");
 System.out.println("========================================");

 // Example 1: Undirected Unweighted Graph
 System.out.println("\n--- Example 1: Undirected Unweighted Graph ---");
 Graph<String> g1 = new Graph<>(false, false);

 g1.addEdge("A", "B")
 .addEdge("A", "C")
 .addEdge("B", "C")
 .addEdge("B", "D")
 .addEdge("C", "D");

 g1.display();

 System.out.println("\nAdjacency Tests:");
 System.out.println("Is A adjacent to C? " + g1.isAdjacent("A", "C"));
 System.out.println("Is A adjacent to D? " + g1.isAdjacent("A", "D"));

 System.out.println("\nNeighbors of B: " + g1.getNeighbors("B"));
 System.out.println("Degree of B: " + g1.getDegree("B")[0]);
 System.out.println("Is graph connected? " + g1.isConnected());

 System.out.println("\n--- Handshaking Theorem Verification ---");
 g1.verifyHandshaking();

 // Example 2: Directed Weighted Graph
 System.out.println("\n\n--- Example 2: Directed Weighted Graph ---");
 Graph<String> g2 = new Graph<>(true, true);

 g2.addEdge("A", "B", 5)
 .addEdge("A", "C", 3)
 .addEdge("B", "C", 2)
 .addEdge("B", "D", 4)
 .addEdge("C", "D", 1);

 g2.display();

 int[] degrees = g2.getDegree("B");
 System.out.println("\nIn-degree of B: " + degrees[0]);
 System.out.println("Out-degree of B: " + degrees[1]);

 // Example 3: Using Integer vertices
 System.out.println("\n\n--- Example 3: Integer Vertices ---");
 Graph<Integer> g3 = new Graph<>(false, false);

 g3.addEdge(1, 2)
 .addEdge(1, 3)
 .addEdge(2, 4)
 .addEdge(3, 4)
 .addEdge(4, 5);

 g3.display();
 System.out.println("Is graph connected? " + g3.isConnected());
 }
}
